def solve(s):
    char_index = {}
    max_length = 0
    start_index = 0

    for index, char in enumerate(s):
        if char in char_index and char_index[char] >= start_index:
            start_index = char_index[char] + 1
        char_index[char] = index
        max_length = max(max_length, index - start_index + 1)

    return max_length
